"""RenderDoc MCP Server - AI-assisted graphics debugging via Model Context Protocol."""

import sys
import os
from pathlib import Path

# Version check
REQUIRED_PYTHON = (3, 13)
if sys.version_info[:2] != REQUIRED_PYTHON:
    raise RuntimeError(
        f"renderdoc-mcp requires Python {REQUIRED_PYTHON[0]}.{REQUIRED_PYTHON[1]}, "
        f"but you are using Python {sys.version_info[0]}.{sys.version_info[1]}. "
        f"The bundled renderdoc.pyd is compiled for Python 3.13 only."
    )

# Setup paths for bundled RenderDoc libraries
# lib/ is now inside the package
lib_dir = Path(__file__).parent / "lib"

if lib_dir.exists():
    # Add lib directory to Python search path for renderdoc.pyd
    lib_dir_str = str(lib_dir.resolve())
    if lib_dir_str not in sys.path:
        sys.path.insert(0, lib_dir_str)
    
    # Windows: Add DLL search directory
    if sys.platform == "win32" and hasattr(os, "add_dll_directory"):
        os.add_dll_directory(lib_dir_str)
        # Also add to PATH for legacy DLL loading
        os.environ["PATH"] = lib_dir_str + os.pathsep + os.environ.get("PATH", "")

